16	
17	#include "custom_ar_comm.h"
18	
19	namespace fastertransformer {
20	
21	template<typename T>
22	CustomAllReduceComm<T>::CustomAllReduceComm(size_t rank_size, size_t rank): rank_size_(rank_size), rank_(rank)
23	{
24	    param_.barrier_flag = 0;
25	    // NOTE: assume All Reduce happens within the node (DGX A100)
26	    param_.rank       = rank_;
27	    param_.local_rank = rank_;
28	    param_.node_id    = 0;
29	}
30	
31	template<typename T>
32	CustomAllReduceComm<T>::~CustomAllReduceComm()
33	{
34	    cudaPointerAttributes comm_buffer_attributes, barrier_attributes;
35	    check_cuda_error(cudaPointerGetAttributes(&comm_buffer_attributes, param_.peer_comm_buffer_ptrs[rank_]));
36	    check_cuda_error(cudaPointerGetAttributes(&barrier_attributes, param_.peer_barrier_ptrs[rank_]));
37	    if (comm_buffer_attributes.type == 2) {
38	        check_cuda_error(cudaFree(param_.peer_comm_buffer_ptrs[rank_]));
39	    }
40	    if (barrier_attributes.type == 2) {
41	        check_cuda_error(cudaFree(param_.peer_barrier_ptrs[rank_]));
42	    }
43	}
44	
45	template<typename T>
46	void CustomAllReduceComm<T>::customAllReduce(size_t elts, cudaStream_t stream)
47	{
48	    param_.elts_total   = elts;
49	    param_.barrier_flag = FLAG(param_.barrier_flag + 1);
50	
51	    invokeOneOrTwoShotAllReduceKernel<T>(param_, stream);
52	
53	    // swap back
54	    output_tensor_->at(0).data = (const void*)tmp_tensor_data_;
55	}
56	
57	template<typename T>
58	void CustomAllReduceComm<T>::allocateAndExchangePeerAccessPointer(
59	    std::vector<std::shared_ptr<AbstractCustomComm>>* custom_all_reduce_comms)
60	{
61	    assert(custom_all_reduce_comms->size() == rank_size_);
62	    assert(rank_ == 0);
63	    // Enable Peer to Peer Access
64	    enableP2P(rank_size_);
65	    for (size_t i = 0; i < rank_size_; i++) {
66	        check_cuda_error(cudaSetDevice(i));
67	        check_cuda_error(cudaMalloc(&(param_.peer_comm_buffer_ptrs[i]), CUSTOM_AR_SIZE_THRESHOLD));
68	        check_cuda_error(
69	            cudaMalloc(&(param_.peer_barrier_ptrs[i]), rank_size_ * (MAX_ALL_REDUCE_BLOCKS + 1) * sizeof(uint32_t)));
70	        check_cuda_error(
71	            cudaMemset(param_.peer_barrier_ptrs[i], 0, rank_size_ * (MAX_ALL_REDUCE_BLOCKS + 1) * sizeof(uint32_t)));
72	        T*        current_peer_comm_buffer_ptr = param_.peer_comm_buffer_ptrs[i];
73	        uint32_t* current_peer_barrier_ptr     = param_.peer_barrier_ptrs[i];
74	        // Assume current comm allocates device memory on all ranks (rank_ == 0)
75	        for (size_t j = 1; j < rank_size_; j++) {
76	            static_cast<CustomAllReduceComm<T>*>(custom_all_reduce_comms->at(j).get())
77	                ->param_.peer_comm_buffer_ptrs[i] = current_peer_comm_buffer_ptr;
78	            static_cast<CustomAllReduceComm<T>*>(custom_all_reduce_comms->at(j).get())->param_.peer_barrier_ptrs[i] =
79	                current_peer_barrier_ptr;
80	        }
81	    }
82	
83	    // Set default local_output_buffer_ptr to local peer_comm_buffer_ptrs
84	    for (size_t i = 0; i < rank_size_; i++) {
85	        static_cast<CustomAllReduceComm<T>*>(custom_all_reduce_comms->at(i).get())->param_.local_output_buffer_ptr =
86	            static_cast<CustomAllReduceComm<T>*>(custom_all_reduce_comms->at(i).get())->param_.peer_comm_buffer_ptrs[i];
87	    }
88	}
89	
90	template<typename T>
91	void CustomAllReduceComm<T>::enableP2P(int ngpus)
92	{
93	    int peer_access_available = 0;
94	    for (int i = 0; i < ngpus; i++) {
95	        cudaSetDevice(i);
96	        for (int j = 0; j < ngpus; j++) {
97	            if (i == j) {
98	                continue;
99	            }
100	            cudaDeviceCanAccessPeer(&peer_access_available, i, j);
101	            // Custom AR Kernels need DGX A100 NVSWITCH connections
102	            assert(peer_access_available);
103	            cudaDeviceEnablePeerAccess(j, 0);
104	        }
105	    }
106	}
107	
108	template<typename T>
109	bool CustomAllReduceComm<T>::swapInternalBuffer(std::vector<Tensor>* tensor_buffer, size_t elts)
110	{
111	    // Check if all reduce elts meet the requirement of custom kernels
112	    // If meet, then swap the local comm buffer ptr with output tensor data pointer (avoid additional
113	    // memory movement)
114	    if (rank_size_ > 1 && elts * sizeof(T) <= CUSTOM_AR_SIZE_THRESHOLD) {
115	        tmp_tensor_data_               = (T*)(tensor_buffer->at(0).data);
116	        output_tensor_                 = tensor_buffer;
117	        tensor_buffer->at(0).data      = param_.peer_comm_buffer_ptrs[rank_];
118	        param_.local_output_buffer_ptr = tmp_tensor_data_;
119	        return true;
120	    }
121	    return false;
122	}
123	
124	template<typename T>
125	void initCustomAllReduceComm(std::vector<std::shared_ptr<AbstractCustomComm>>* custom_all_reduce_comms,
126	                             int                                               enable_custom_all_reduce,
127	                             size_t                                            rank_size)
128	{
129	    if (custom_all_reduce_comms == 0) {
130	        // don't use custom all reduce kernels, fall back to NCCL
131	        for (size_t i = 0; i < rank_size; i++) {
132	            custom_all_reduce_comms->push_back(nullptr);
133	        }
134	        return;
135	    }
136	
137	    if (rank_size != RANKS_PER_NODE) {
138	#ifdef BUILD_MULTI_GPU
139	        if (rank_size > 1) {
140	            FT_LOG_WARNING("Custom All Reduce only supports 8 Ranks currently. Using NCCL as Comm.");
141	        }
142	#else
143	        FT_CHECK_WITH_INFO(rank_size == 1,
144	                           fmtstr("Custom All Reduce only supports 8 Ranks currently, got rank_size %ld. FT needs "
145	                                  "the NCCL library to communicate among devices but has built without NCCL. "
146	                                  "Please use the flag -DBUILD_MULTI_GPU=ON when compiling.",
147	                                  rank_size));
148	#endif
149	        for (size_t i = 0; i < rank_size; i++) {
150	            custom_all_reduce_comms->push_back(nullptr);
151	        }
152	        return;
153	    }
154	
155	#if defined(CUDART_VERSION) && CUDART_VERSION >= 11020
156	    for (size_t i = 0; i < rank_size; i++) {
157	        custom_all_reduce_comms->push_back(std::make_shared<CustomAllReduceComm<T>>(rank_size, i));
158	    }
159	    custom_all_reduce_comms->at(0)->allocateAndExchangePeerAccessPointer(custom_all_reduce_comms);
160	#else
161	    FT_LOG_WARNING("Custom All Reduce is not supported before CUDA 11.2. Using NCCL as Comm.");
162	    for (size_t i = 0; i < rank_size; i++) {
163	        custom_all_reduce_comms->push_back(nullptr);
164	    }
165	#endif
166	}
167	
168	// Template instantiation
169	template class CustomAllReduceComm<uint16_t>;
170	#ifdef ENABLE_BF16
171	template class CustomAllReduceComm<__nv_bfloat16>;
172	#endif
173	template class CustomAllReduceComm<uint32_t>;
174	template void
175	initCustomAllReduceComm<uint16_t>(std::vector<std::shared_ptr<AbstractCustomComm>>* custom_all_reduce_comms,
176	                                  int                                               enable_custom_all_reduce,
177	                                  size_t                                            rank_size);
178	#ifdef ENABLE_BF16
179	template void
180	initCustomAllReduceComm<__nv_bfloat16>(std::vector<std::shared_ptr<AbstractCustomComm>>* custom_all_reduce_comms,
181	                                       int                                               enable_custom_all_reduce,
182	                                       size_t                                            rank_size);
183	#endif
184	template void
185	initCustomAllReduceComm<uint32_t>(std::vector<std::shared_ptr<AbstractCustomComm>>* custom_all_reduce_comms,
186	                                  int                                               enable_custom_all_reduce,
187	                                  size_t                                            rank_size);
188	
189	}  // namespace fastertransformer
