138	template<typename T>
139	static __global__ void oneShotAllReduceKernel(AllReduceParams<T> params)
140	{
141	    // The block index.
142	    const int bidx = blockIdx.x;
143	    // The thread index with the block.
144	    const int tidx = threadIdx.x;
145	
146	    // The number of elements packed into one for comms
147	    static constexpr int NUM_ELTS = std::is_same<T, uint32_t>::value ? 4 : 8;
148	
149	    // Packed data type for comms
150	    using PackedType = typename ARTypeConverter<T>::Type;
151	
152	    // The location in the destination array (load 8 fp16 or load 4 fp32 using LDG.128).
153	    size_t offset = bidx * params.elts_per_block + tidx * NUM_ELTS;
154	    // The end of the segment computed by that block.
155	    size_t max_offset = std::min((bidx + 1) * params.elts_per_block, params.elts_per_rank);
156	
157	    // Synchronize the ranks.
158	    volatile uint32_t* barrier_d = params.peer_barrier_ptrs[params.local_rank];
159	    if (tidx < RANKS_PER_NODE) {
160	        // The 1st block notifies the other ranks.
161	        if (bidx == 0) {
162	            params.peer_barrier_ptrs[tidx][params.local_rank] = params.barrier_flag;
163	        }
164	
165	        // Busy-wait until all ranks are ready.
166	        while (barrier_d[tidx] < params.barrier_flag) {}
167	    }
168	
169	    // Make sure we can move on...
170	    __syncthreads();
171	
172	    // The source pointers. Distributed round-robin for the different warps.
173	    const T* src_d[RANKS_PER_NODE];
174	#pragma unroll
175	    for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
176	        int rank  = (params.local_rank + ii) % RANKS_PER_NODE;
177	        src_d[ii] = params.peer_comm_buffer_ptrs[rank];
178	    }
179	
180	    // Each block accumulates the values from the different GPUs on the same node.
181	    for (size_t iter_offset = offset; iter_offset < max_offset; iter_offset += blockDim.x * NUM_ELTS) {
182	        // Iterate over the different ranks/devices on the node to load the values.
183	        PackedType vals[RANKS_PER_NODE];
184	#pragma unroll
185	        for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
186	            vals[ii] = reinterpret_cast<const PackedType*>(&src_d[ii][iter_offset])[0];
187	        }
188	
189	        // Sum the values from the different ranks.
190	        PackedType sums = init_packed_type<PackedType>();
191	#pragma unroll
192	        for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
193	            sums = add128b<PackedType, T>(sums, vals[ii]);
194	        }
195	
196	        // Store to the destination buffer.
197	        reinterpret_cast<PackedType*>(&params.local_output_buffer_ptr[iter_offset])[0] = sums;
198	    }
199	}
200	
201	template<typename T>
202	static __global__ void twoShotAllReduceKernel(AllReduceParams<T> params)
203	{
204	
205	    // The block index.
206	    const int bidx = blockIdx.x;
207	    // The thread index with the block.
208	    const int tidx = threadIdx.x;
209	
210	    // The number of elements packed into one for comms
211	    static constexpr int NUM_ELTS = std::is_same<T, uint32_t>::value ? 4 : 8;
212	
213	    // Packed data type for comms
214	    using PackedType = typename ARTypeConverter<T>::Type;
215	
216	    // The location in the destination array (load 8 fp16 or load 4 fp32 using LDG.128).
217	    size_t offset = bidx * params.elts_per_block + tidx * NUM_ELTS + params.rank_offset;
218	    // The end of the segment computed by that block.
219	    size_t max_offset = min(offset + params.elts_per_block, params.elts_total);
220	
221	    // Synchronize the ranks.
222	    volatile uint32_t* barrier_d = params.peer_barrier_ptrs[params.local_rank];
223	    if (tidx < RANKS_PER_NODE) {
224	        // The 1st block notifies the other ranks.
225	        if (bidx == 0) {
226	            params.peer_barrier_ptrs[tidx][params.local_rank] = params.barrier_flag;
227	        }
228	
229	        // Busy-wait until all ranks are ready.
230	        while (barrier_d[tidx] < params.barrier_flag) {}
231	    }
232	
233	    // Make sure we can move on...
234	    __syncthreads();
235	
236	    // The source pointers. Distributed round-robin for the different warps.
237	    T* src_d[RANKS_PER_NODE];
238	    // The destination ranks for round-robin gathering
239	    size_t dst_rank[RANKS_PER_NODE];
240	#pragma unroll
241	    for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
242	        int rank     = (params.local_rank + ii) % RANKS_PER_NODE;
243	        src_d[ii]    = params.peer_comm_buffer_ptrs[rank];
244	        dst_rank[ii] = rank;
245	    }
246	
247	    // Each block accumulates the values from the different GPUs on the same node.
248	    for (size_t local_offset = offset; local_offset < max_offset; local_offset += blockDim.x * NUM_ELTS) {
249	
250	        // Iterate over the different ranks/devices on the node to load the values.
251	        PackedType vals[RANKS_PER_NODE];
252	#pragma unroll
253	        for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
254	            vals[ii] = reinterpret_cast<const PackedType*>(&src_d[ii][local_offset])[0];
255	        }
256	
257	        // Sum the values from the different ranks.
258	        PackedType sums = init_packed_type<PackedType>();
259	#pragma unroll
260	        for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
261	            sums = add128b<PackedType, T>(sums, vals[ii]);
262	        }
263	
264	        // Store to the local buffer.
265	        reinterpret_cast<PackedType*>(&src_d[0][local_offset])[0] = sums;
266	    }
267	
268	    // sync threads to make sure all block threads have the sums
269	    __syncthreads();
270	
271	    // barreris among the blocks with the same idx (release-acuqire semantics)
272	    if (tidx < RANKS_PER_NODE) {
273	        // The all blocks notifies the other ranks.
274	        uint32_t flag_block_offset = RANKS_PER_NODE + bidx * RANKS_PER_NODE;
275	        st_flag_release(params.barrier_flag, params.peer_barrier_ptrs[tidx] + flag_block_offset + params.local_rank);
276	
277	        // Busy-wait until all ranks are ready.
278	        uint32_t  rank_barrier   = 0;
279	        uint32_t* peer_barrier_d = params.peer_barrier_ptrs[params.local_rank] + flag_block_offset + tidx;
280	        do {
281	            ld_flag_acquire(rank_barrier, peer_barrier_d);
282	        } while (rank_barrier != params.barrier_flag);
283	    }
284	
285	    // sync threads to make sure all other ranks has the final partial results
286	    __syncthreads();
287	
288	    // Gather all needed elts from other intra-node ranks
289	    for (size_t local_offset = offset; local_offset < max_offset; local_offset += blockDim.x * NUM_ELTS) {
290	#pragma unroll
291	        for (int ii = 0; ii < RANKS_PER_NODE; ++ii) {
292	            // use round-robin gathering from other ranks
293	            int offset_rank = local_offset + (dst_rank[ii] - params.local_rank) * params.elts_per_rank;
294	            reinterpret_cast<PackedType*>(&params.local_output_buffer_ptr[offset_rank])[0] =
295	                reinterpret_cast<PackedType*>(&src_d[ii][offset_rank])[0];
296	        }
297	    }
298	}
299	
300	////////////////////////////////////////////////////////////////////////////////////////////////////
301	
302	void kernelLaunchConfig(
303	    int& blocks_per_grid, int& threads_per_block, size_t elts, int kernel_algo, size_t data_type_bytes)
304	{
305	    assert(data_type_bytes == 2 || data_type_bytes == 4);
306	    // NOTE: need to support FP16 and FP32
307	    size_t elts_per_thread = 16 / data_type_bytes;
308	    size_t elts_per_warp   = (16 * WARP_SIZE) / data_type_bytes;
309	    switch (kernel_algo) {
310	        case 0: {  // one stage all reduce algo
311	            assert(elts % elts_per_warp == 0);
312	            if (elts < (elts_per_thread * DEFAULT_BLOCK_SIZE)) {  // local reduce
313	                threads_per_block = ((elts + elts_per_warp - 1) / elts_per_warp) * WARP_SIZE;
314	                blocks_per_grid   = 1;
315	            }
316	            else {  // local reduce
317	                if (elts % (elts_per_thread * threads_per_block) == 0) {
318	                    blocks_per_grid =
319	                        (elts + elts_per_thread * threads_per_block - 1) / (elts_per_thread * threads_per_block);
320	                    // NOTE: need to adjust here
321	                    if (blocks_per_grid > MAX_ALL_REDUCE_BLOCKS) {
322	                        int iter_factor = 1;
323	                        while (blocks_per_grid / iter_factor > MAX_ALL_REDUCE_BLOCKS || blocks_per_grid % iter_factor) {
324	                            iter_factor += 1;
325	                        }
326	                        blocks_per_grid /= iter_factor;
327	                    }
328	                }
329	                else {
330	                    int total_threads = elts / elts_per_thread;
331	                    blocks_per_grid   = 1;
332	                    while (total_threads % blocks_per_grid != 0
333	                           || total_threads / blocks_per_grid > DEFAULT_BLOCK_SIZE) {
334	                        blocks_per_grid += 1;
335	                    }
336	                    threads_per_block = total_threads / blocks_per_grid;
337	                }
338	            }
339	            break;
340	        }
341	        case 1: {  // two stage all reduce algo
342	            int total_threads = elts / RANKS_PER_NODE / RANKS_PER_NODE;
343	            assert(elts / RANKS_PER_NODE % RANKS_PER_NODE == 0 && total_threads % WARP_SIZE == 0);
344	
345	            while (total_threads % blocks_per_grid != 0 || total_threads / blocks_per_grid > DEFAULT_BLOCK_SIZE) {
346	                blocks_per_grid += 1;
347	            }
348	
349	            threads_per_block = total_threads / blocks_per_grid;
350	
351	            // NOTE: need to adjust here
352	            if (blocks_per_grid > MAX_ALL_REDUCE_BLOCKS) {
353	                int iter_factor = 1;
354	                while (blocks_per_grid / iter_factor > MAX_ALL_REDUCE_BLOCKS || blocks_per_grid % iter_factor) {
355	                    iter_factor += 1;
356	                }
357	                blocks_per_grid /= iter_factor;
358	            }
359	            break;
360	        }
361	    }
362	}
363	
364	////////////////////////////////////////////////////////////////////////////////////////////////////
365	
366	template<typename T>
367	void invokeOneOrTwoShotAllReduceKernel(AllReduceParams<T>& param, cudaStream_t stream)
368	{
369	    size_t elts_total      = param.elts_total;
370	    int    blocks_per_grid = 1, threads_per_block = DEFAULT_BLOCK_SIZE;
371	    int    kernel_algo = 1;
372	    if (elts_total * sizeof(T) <= DEFALUT_ALGO_AR_SIZE_THRESHOLD) {
373	        kernel_algo = 0;
374	    }
375	
376	    kernelLaunchConfig(blocks_per_grid, threads_per_block, elts_total, kernel_algo, sizeof(T));
377	
378	    if (kernel_algo == 0) {
379	        param.elts_per_rank  = elts_total;
380	        param.elts_per_block = param.elts_per_rank / blocks_per_grid;
381	        oneShotAllReduceKernel<<<blocks_per_grid, threads_per_block, 0, stream>>>(param);
382	    }
383	    else {
384	        param.elts_per_rank  = param.elts_total / RANKS_PER_NODE;
385	        param.elts_per_block = param.elts_per_rank / blocks_per_grid;
386	        param.rank_offset    = param.rank * param.elts_per_rank;
387	        twoShotAllReduceKernel<<<blocks_per_grid, threads_per_block, 0, stream>>>(param);
388	    }
389	}
390	
391	// Template instantiation
392	template void invokeOneOrTwoShotAllReduceKernel<uint16_t>(AllReduceParams<uint16_t>& param, cudaStream_t stream);
393	#ifdef ENABLE_BF16
394	template void invokeOneOrTwoShotAllReduceKernel<__nv_bfloat16>(AllReduceParams<__nv_bfloat16>& param,
395	                                                               cudaStream_t                    stream);
396	#endif
397	template void invokeOneOrTwoShotAllReduceKernel<uint32_t>(AllReduceParams<uint32_t>& param, cudaStream_t stream);
398	}  // namespace fastertransformer
